    $role = (string)($userRow['role'] ?? 'customer');
    $status = (string)($userRow['status'] ?? 'active');

    if ($role === 'admin') {
        $adminCount++;
    } elseif ($role === 'operator') {
        $operatorCount++;
    } else {
        $customerCount++;
    }

    if ($status === 'active') {
        $activeCount++;
    }
}

